const match = $input.first().json;
const body = $('Webhook match-status').first().json.body;

const newStatus = body.status;
const oldMatchState = match.match_state;

const typeMap = {
  '1H':  'match_kickoff',
  'HT':  'match_halftime',
  '2H':  'match_second_half',
  'FT':  'match_fulltime',
  'ET':  'match_extra_kickoff',
  'BT':  'match_extra_halftime',
  'P':   'match_penalties',
  'AET': 'match_fulltime_aet',
  'PEN': 'match_fulltime_pen'
};

const newMatchStateMap = {
  '1H':  'Live',
  'HT':  'Live',
  '2H':  'Live',
  'FT':  'FullTime',
  'ET':  'Live',
  'BT':  'Live',
  'P':   'Live',
  'AET': 'FullTime',
  'PEN': 'FullTime'
};

const matchPhaseMap = {
  '1H':  'FirstHalf',
  'HT':  'FirstHalfBreak',
  '2H':  'SecondHalf',
  'FT':  'FullTime',
  'ET':  'SecondHalf',
  'BT':  'FirstHalfBreak',
  'P':   'SecondHalf',
  'AET': 'FullTime',
  'PEN': 'FullTime'
};

const validFromStates = {
  '1H':  ['PreMatch', 'ToBeConfirmed', null],
  'HT':  ['Live'],
  '2H':  ['Live'],
  'FT':  ['Live', 'FullTime'],
  'ET':  ['Live', 'FullTime'],
  'BT':  ['Live'],
  'P':   ['Live'],
  'AET': ['Live', 'FullTime'],
  'PEN': ['Live', 'FullTime']
};

const allowedStates = validFromStates[newStatus] ?? [];
const isValid = !!typeMap[newStatus] && (
  allowedStates.includes(oldMatchState) || allowedStates.includes(null)
);

if (!isValid) {
  return [{ json: { is_valid_transition: false } }];
}

const ticker_mode = body.ticker_mode ?? match.ticker_mode ?? 'coop';

const base = {
  match_id: match.id,
  fixture_id: match.external_id,
  new_match_state: newMatchStateMap[newStatus] ?? oldMatchState,
  new_match_phase: matchPhaseMap[newStatus] ?? null,
  minute: body.minute ?? null,
  ticker_mode,
  is_valid_transition: true,
};

const isFulltime = ['FT', 'AET', 'PEN'].includes(newStatus);

if (isFulltime) {
  const phases = [
    { event_type: 'match_kickoff',     minute: 1  },
    { event_type: 'match_halftime',    minute: 45 },
    { event_type: 'match_second_half', minute: 46 },
    { event_type: typeMap[newStatus],  minute: body.minute ?? 90 },
  ];
  if (newStatus === 'AET') {
    phases.splice(3, 0,
      { event_type: 'match_extra_kickoff',  minute: 91  },
      { event_type: 'match_extra_halftime', minute: 105 }
    );
  }
  if (newStatus === 'PEN') {
    phases.splice(3, 0,
      { event_type: 'match_extra_kickoff',  minute: 91  },
      { event_type: 'match_extra_halftime', minute: 105 },
      { event_type: 'match_fulltime_aet',   minute: 120 },
      { event_type: 'match_penalties',      minute: 121 }
    );
  }
  return phases.map(p => ({ json: { ...base, ...p } }));
}

return [{ json: { ...base, event_type: typeMap[newStatus] } }];

// Style wird jetzt zentral im Backend gesetzt:
// ef_whitelabel + neutral → automatisch euphorisch
const ticker_mode = $('Webhook match-status').first().json.body.ticker_mode
  ?? $('SQL: Match laden').first().json.ticker_mode
  ?? 'coop';
const instance = $('SQL: Match laden').first().json.instance || 'generic';
return [{ json: {
  id: $json.id,
  type: $json.type,
  match_id: $('SQL: Match laden').first().json.id,
  style: 'neutral',
  ticker_mode,
  instance
} }];

// Parallel-Branch: läuft für JEDE gültige Transition,
// unabhängig ob Ticker-Eintrag schon existiert.
// Nur für HT und FT wird match-summary ausgelöst.
const summaryPhaseMap = {
  match_halftime: 'Halftime',
  match_fulltime: 'After',
  match_fulltime_aet: 'After',
  match_fulltime_pen: 'After',
};
const eventType = $json.event_type;
const summaryPhase = summaryPhaseMap[eventType];
if (!summaryPhase) return [];

const ticker_mode = $('Webhook match-status').first().json.body.ticker_mode
  ?? $('SQL: Match laden').first().json.ticker_mode
  ?? 'coop';
const style = $('Webhook match-status').first().json.body.style ?? 'neutral';

return [{ json: {
  match_id: $json.match_id,
  phase: summaryPhase,
  style,
  ticker_mode
} }];
